var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"5년 후 현재","JPN":"5年後、現在","ENG":"5 years later, present day","TWN":"5年後的現在"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"프론트 베이 격벽 <color=#ffd34c>징역노동자 근무구역</color> ","JPN":"フロントベイの隔壁、<color=#ffd34c>懲役労働者の勤務エリア</color> ","ENG":"Front Bay Bulwark <color=#ffd34c>Sentenced Laborer Area</color>","TWN":"前灣隔離牆<color=#ffd34c>服勞役區域</color> "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"기준치 이상의 침식파가 감지되었습니다.","JPN":"基準値以上の侵食波が感知されました。","ENG":"An abnormally high Corruption ray has been detected.","TWN":"已偵測超出基準值的侵蝕波。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"격벽 노동자분들은 모두 지정된 대피소로 이동해주시기 바랍니다.","JPN":"隔壁の労働者の皆さんは、指定された避難所まで移動してください。","ENG":"All bulwark workers, please proceed to the designated shelters.","TWN":"隔離牆作業人員請立即前往指定避難所。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"다시 한번 알려드립니다.","JPN":"もう一度お知らせします。","ENG":"I repeat.","TWN":"再重複一次。"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"격벽 노동자분들은…….","JPN":"隔壁の労働者の皆さんは……","ENG":"All bulwark workers...","TWN":"隔離牆作業人員請……"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장, 검은 범람이 끝난 지 얼마나 됐다고 벌써 이런 일이 일어나는 거야?","JPN":"くそっ、つい最近黒い氾濫が終わったばかりだってのに、またか？","ENG":"Damn it, how long's it been since the Black Flood ended? Why's this happening already?","TWN":"可惡。黑色洪災才剛結束，怎麼又來了？"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L12_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_MONITOR","text":{"KOREA":"격벽 보수 공사는 중지해!","JPN":"隔壁の補修工事は中止だ！","ENG":"Stop all bulwark repairs!","TWN":"立刻停止隔離牆修復工程！"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_MONITOR","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_MONITOR","text":{"KOREA":"침식체들이 기어 올라오기 전에 서둘러 대피해라!","JPN":"侵食体どもが這いあがってくる前に急いで避難しろ！","ENG":"Evacuate before the C.O.s start crawling up here!","TWN":"在侵蝕體爬上來之前盡快撤離！"},"stage":{"bg":"FRONTBAY_WALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_MONITOR","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"……이상으로 현 상황에 대한 보고를 마칩니다.","JPN":"……以上で現状況についての報告を終わります。","ENG":"...That concludes my report on the current situation.","TWN":"……以上為現況報告。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"솔직히 말하면, 무척이나 당황스럽군.","JPN":"正直言って、かなり動揺している。","ENG":"To be honest, this is quite baffling.","TWN":"說實話我很震驚。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>검은 범람</color>이 다시 발생했다고?","JPN":"<color=#ffd34c>黒い氾濫</color>がまた発生しただと？","ENG":"The <color=#ffd34c>Black Flood</color> has returned?","TWN":"又發生<color=#ffd34c>黑色洪災</color>了？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"저도 관측 결과가 의심스러워 몇 번이고 다시 조사했지만…….","JPN":"私も観測の結果が疑わしく、何度も調べたのですが……","ENG":"I rechecked the readings several times myself because they seemed off, but...","TWN":"我懷疑觀測結果，反覆檢查了好幾次……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"상황을 받아들이지 못하겠다는 것이 아니야.","JPN":"状況が飲み込めないわけではないんだ。","ENG":"It's not that I can't accept the situation.","TWN":"我不是不能接受現實。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"검은 범람의 주기는 계속해서 짧아지고 있었으니까.","JPN":"黒い氾濫の周期はどんどん短くなってきていたからな。","ENG":"The Black Flood's cycle has been growing shorter and shorter.","TWN":"畢竟黑色洪災的週期越來越短。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"다만…….","JPN":"ただ……","ENG":"It's just that...","TWN":"只是……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그걸 고려해도 지나치게 빨라요.","JPN":"それを考慮しても早すぎます。","ENG":"Even accounting for that, this is far too soon.","TWN":"就算如此，這也太快了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"놈은 얼마 전, 인빈서블의 자폭으로 본체에 큰 타격을 입었습니다.","JPN":"クラーケンは直前の氾濫の際、インビンシブルの自爆によって本体に大きなダメージを受けました。","ENG":"The creature took heavy damage from the Invincible's self-destruction not long ago.","TWN":"那傢伙不久前才被無敵號自爆重創本體。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그 상처를 회복하는 데 몇 년은 걸릴 거라 예상했는데…….","JPN":"その怪我が回復するのに数年はかかると予想していたのに……","ENG":"We estimated it would take years for it to recover from that...","TWN":"我原本以為至少得花好幾年才能恢復……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L31_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그라운드 원의 시니어 르네께서 긴급한 통신을 요청하셨습니다.","JPN":"グラウンド・ワンのシニア・ルネから、緊急通信の要請です。","ENG":"Senior Renée of Ground One is requesting an urgent transmission.","TWN":"G1的Senior芮妮緊急請求通話。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"연결할까요?","JPN":"繋げましょうか？","ENG":"Shall I connect her?","TWN":"要接通嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"시니어 르네가 직접 연락할 정도면 보통 사안이 아니겠지.","JPN":"シニア・ルネが直接連絡してくるくらいだ。きっとただ事ではない。","ENG":"If Senior Renée is contacting us directly, it must be serious.","TWN":"竟能讓Senior芮妮親自聯絡，事情絕對不簡單。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"연결해 줘.","JPN":"繋げてくれ。","ENG":"Put her through.","TWN":"接吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"근육남! 그쪽 상황은 좀 괜찮아?!","JPN":"筋肉男！　そっちは大丈夫か！？","ENG":"Muscle-head! Are you all holding up over there?!","TWN":"肌肉男！你們那邊沒事吧？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"안부를 나눌 새도 없이 말하는 것을 보니 그쪽에도 무슨 일이 생긴 모양이군.","JPN":"挨拶を交わす間もなく本題から入るのをみると、そっちにも何かあったんだな。","ENG":"If you're skipping the pleasantries, something's happened on your end too.","TWN":"連問候都省了，看來你們那邊也出事了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"검은 범람이 시작되었다는 보고를 받았어.","JPN":"こちらは、黒い氾濫が始まったという報告を受けたところだが。","ENG":"We received a report the Black Flood has begun.","TWN":"我收到黑色洪災啟動的報告。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"설마… 대균열에 관한 문제가 생긴 건가?","JPN":"まさか……大亀裂絡みの問題が発生したのか？","ENG":"Wait... Is something wrong with the Grand Dimension Crevice?","TWN":"難道……大峽谷發生什麼問題了？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……역시 히키코모리보다는 눈치가 빠르네.","JPN":"……やはり、引きこもりよりは勘が鋭いな。","ENG":"...As expected, you're quicker on the uptake than that shut-in.","TWN":"……你果然比宅男敏銳。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 지금 전 세계의 대균열이 확장하기 시작했어.","JPN":"そうだ。今、全世界の大亀裂が拡張し始めている。","ENG":"Yes. The Grand Dimension Crevices all over the world are starting to expand.","TWN":"沒錯。現在全世界的大峽谷都開始擴張。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"대균열의 확장이라… 그래서 크라켄이 움직이기 시작한 거였군.","JPN":"大亀裂の拡張……それでクラーケンが動き出したわけか。","ENG":"Expansion of the Grand Dimension Crevices... so that's why Kraken began to move.","TWN":"大峽谷擴張……所以克拉肯才會開始移動。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래. 크라켄은 대균열을 막는 마개 역할을 하고 있던 침식체.","JPN":"ああ。クラーケンは大亀裂を塞ぐ栓の役割をしていた侵食体。","ENG":"Right. Kraken was a C.O. acting as a stopper that kept the Grand Dimension Crevice sealed.","TWN":"對。克拉肯原本是蓋住大峽谷的蓋子。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그런 녀석이 대균열이 확장하자마자 움직였다는 것은…….","JPN":"そんなやつが大亀裂の拡張が始まるや否や動いたということは……","ENG":"For it to move the moment the Grand Dimension Crevice expanded means...","TWN":"大峽谷一擴張那傢伙就立刻開始移動，那就代表……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"더 이상 크라켄으로는 감당할 수 없을 만큼 대균열이 벌어졌다는 뜻이겠지.","JPN":"もうクラーケンでは塞ぎきれないほど大亀裂が大きくなってしまったということだろうな。","ENG":"The Grand Dimension Crevice has widened beyond what Kraken can hold back.","TWN":"大峽谷大到克拉肯也壓不住了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 그렇게 되면……?","JPN":"待てよ、そうなると……？","ENG":"Hold on, if that's true...?","TWN":"等等，那麼……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Exactly.","TWN":"沒錯。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"프론트 베이로 밀려오는 파도에 섞여 있는 건 크라켄에게 떠밀려진 바다의 침식체 뿐만이 아닐 거다.","JPN":"フロントベイに打ち寄せる波に乗りやってくるのは、クラーケンに押し出された海の侵食体だけではなさそうだ。","ENG":"The waves pushing toward Front Bay won't just be carrying sea C.O.s shoved aside by Kraken.","TWN":"隨海潮湧向前灣的，不會只有被克拉肯推來的海洋侵蝕體。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"벨라미. 당장 최고 등급 재난 경보를 발령해.","JPN":"ベラミー。今すぐ最高ランクの災難警報を発令しろ。","ENG":"Bellamy. Issue the highest-level disaster alert immediately.","TWN":"貝拉米，立刻發布最高級災難警報。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"나는 해저 대감옥으로 가야겠어.","JPN":"私は海底大監獄に向かう。","ENG":"I'm heading to the Deepsea Gaol.","TWN":"我要去海底大監獄。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"네? 해저 대감옥이요?","JPN":"えっ？　海底大監獄ですか？","ENG":"What? The Deepsea Gaol?","TWN":"什麼？海底大監獄？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그렇다면 설마…….","JPN":"それって、まさか……","ENG":"Don't tell me...","TWN":"難道你是……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그래. 공인 카운터가 요양 중인 지금, 이 사태를 해결해 줄 수도 있는 사람은…….","JPN":"ああ。公認カウンターが療養中である今、この事態を解決できる可能性のある人物は……","ENG":"Yes. With our Official Counter still recuperating, the only person who might resolve this...","TWN":"對。現在公證制裁者在療傷，能解決這狀況的人……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그 녀석일지도 모르니까 말이지.","JPN":"あいつになるかもしれないからな。","ENG":"Might be that one.","TWN":"或許只有那傢伙了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장! 왜 갑자기 지진이……?","JPN":"くそ！　なんで急に地震が……？","ENG":"Damn it! Why's there an earthquake all of a sudden...?","TWN":"可惡！為什麼突然地震……？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"얼른 본부에 연락해서 지원 요청을……!","JPN":"早く本部に連絡して支援要請を……！","ENG":"I need to contact HQ for backup...!","TWN":"快聯絡本部請求支援……！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"누가 연락하게 해 준대?","JPN":"させるかよ。","ENG":"Who said you could call anyone?","TWN":"誰讓你們聯絡了？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"키, 키이라? 어느새……!","JPN":"キ、キーラ？　いつの間に……！","ENG":"K-Kiera?! When did you–?!","TWN":"琪、琪伊拉？妳什麼時候……！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"답답해서 미쳐버리는 줄 알았다, 임마.","JPN":"もどかしくて気が狂うかと思ったぜ。","ENG":"I was going crazy cooped up in here, idiot.","TWN":"我快悶到發瘋了，笨蛋。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"갑자기 감옥 문이 열려서 다행이지, 조금만 더 있었으면 큰일 날 뻔했다니까?","JPN":"いきなり監獄の扉が開いたから助かったけど、もう少し遅れてたら大変なことになるところだったんだぞ。","ENG":"Good thing the cell door suddenly opened. A little longer and I'd have snapped.","TWN":"幸好牢門突然開了，要是我再待久一點就糟了哦？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"이, 이봐! 여긴 바다 깊은 곳에 있는 감옥이야.","JPN":"お、おい！　この監獄は海の深い場所にあるんだ。","ENG":"H-hey! This is a deep-sea containment facility!","TWN":"喂、喂！這裡可是海底深處的監獄。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"여기서 나가봤자 만날 수 있는 건 소금물과 침식체들 뿐이라고!","JPN":"ここから出ても、目の前にあるのは海水と侵食体だけだぞ！","ENG":"Even if you escape, all you'll find out there are seawater and C.O.s!","TWN":"出去後只會遇到海水和侵蝕體啊！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"너희들이 오고 갈 수 있는 운송 기관이 있겠지.","JPN":"お前らが行き来するのに使う運送手段があるだろ？","ENG":"You guys must have some transport to get in and out.","TWN":"你們肯定有可以進出這地方的運輸工具。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"감옥째로 수장당하고 싶지 않으면 얌전히 그곳으로 안내해.","JPN":"監獄ごと沈みたくなかったら、大人しくそこまで案内しろ。","ENG":"If you don't want this whole place sinking, take me to it.","TWN":"要是不想被囚禁在監獄裡，就乖乖帶我去。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"그런 말도 안 되는 요구를……!","JPN":"そんな無茶な……！","ENG":"Th-that's absurd...!","TWN":"這麼荒唐的要求……！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"평범한 지진이 아닌 것 같은데.","JPN":"普通の地震じゃないみたいだけど。","ENG":"This isn't a normal quake.","TWN":"這好像不是普通的地震。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"건물 밖에 무슨 일이 일어나고 있는 거야?","JPN":"外で何かあったのか？","ENG":"What's happening outside the building?","TWN":"外面到底發生什麼事了？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"흥, 시치미 떼고 있긴.","JPN":"ふん、しらばくれるな。","ENG":"Hmph. Playing dumb now?","TWN":"哼，妳還裝。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"네가 일으킨 지진을 마치 건물 밖에서 일어난 일인 양 꾸미려는 거냐?","JPN":"地震はお前が起こしているくせに、建物の外で起きているふりをするつもりか？","ENG":"Trying to pretend the quake you caused is something happening outside?","TWN":"妳想把妳引發的地震說成外面的事嗎？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"……?","JPN":"……？","ENG":"...?","TWN":"……？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"무슨 소리야, 나는 구속구에 의해…….","JPN":"何言ってるんだ、あたしは拘束具で……","ENG":"What are you talking about? I'm restrained by–","TWN":"你在說什麼，我被束具……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"네가 수십 개의 출력 제어 구속구를 끊은 나머지…….","JPN":"お前が数十個にも及ぶ出力制御拘束具を壊して……","ENG":"You broke dozens of those output restraints...","TWN":"妳把幾十個輸出控制束具都扯斷……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"프론트 베이의 수많은 공학자가 피눈물을 흘리며 야근을 한 이야기는 이미 유명하다고!","JPN":"フロントベイの数多くの工学者が血の涙を流しながら残業したってのは有名な話だからな！","ENG":"Half the engineers in Front Bay bled their eyes dry working overtime on those things!","TWN":"害前灣一堆工程師加班加到哭的事早就傳開了！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"아니, 그러니까 이 구속구는 그냥 시니어가…….","JPN":"いや、だからこの拘束具はシニアが……","ENG":"No, listen. These restraints were just something the Senior–","TWN":"不是，我是說那些束具是Senior……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장! 너는 그 피눈물이 들어간 구속구조차 소용없었던 거였나?!","JPN":"くそ！　お前には血の涙が染み込んだ拘束具さえも意味がなかったっていうのか！？","ENG":"Damn it! Even restraints forged in blood and sweat don't work on you?!","TWN":"可惡！連融入工程師血淚的束具都擋不住妳？！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"맞아.","JPN":"そうさ。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"난 프론트 베이 공학자들의 피눈물이 섞인 구속구를 무용지물로 만들고,","JPN":"あたしはフロントベイの工学者たちの血の涙が混ざった拘束具を使い物にならなくし、","ENG":"I shattered every tear-soaked restraint made by Front Bay's engineers,","TWN":"是我讓工程師流著血淚製作的束具失效，"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"건물 밖에 지진이 난 것처럼 위장해서 너를 인질 삼아 이곳에서 탈출하려고 했어.","JPN":"建物の外で地震が発生したように見せかけて、お前を人質に取りここから脱出しようとした。","ENG":"Faked the quakes as if they were happening outside, and planned to use you as a hostage to escape.","TWN":"再把外頭的震動偽裝成地震，挾持你逃出這裡。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"역시 프론트 베이 최악의 범죄자!","JPN":"やはりフロントベイ最悪の犯罪者だな！","ENG":"As expected of Front Bay's worst criminal!","TWN":"不愧是前灣最惡劣的罪犯！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"내 눈은 속일 수 없지!","JPN":"私の目は誤魔化されないぞ！","ENG":"You can't fool my eyes!","TWN":"絕對騙不過我的眼睛！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 난 너의 그 간악한 계획에 넘어가지 않아!","JPN":"お前のその卑劣な手になど乗るものか！","ENG":"But I won't fall for your vile scheme!","TWN":"但我不會被妳卑劣的計畫蒙騙！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"왜냐하면 나는…….","JPN":"なぜなら、私は……","ENG":"Because I am–","TWN":"因為我……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"위험해!","JPN":"危ない！","ENG":"Watch out!","TWN":"危險！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"꺅!","JPN":"きゃっ！","ENG":"Kyaaah!","TWN":"呀啊！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"생긴 건 듬직하게 생겨서는…….","JPN":"頼もしいのは見かけだけかよ……","ENG":"You look tough, but you sure fall apart fast...","TWN":"長得那麼壯……"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"나, 날 구해준 거냐?","JPN":"た、助けてくれたのか？","ENG":"D-did you just save me?","TWN":"妳、妳救了我？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"눈앞에서 사람 죽는 거 구경하는 취미는 없어.","JPN":"目の前で人が死ぬのを見物する趣味はないんでね。","ENG":"I don't enjoy watching people die right in front of me.","TWN":"我沒興趣看到有人死在我眼前。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그나저나, 관리국 감옥에는 침식체도 가둘 수 있어?","JPN":"それより、管理局の監獄には侵食体も閉じ込めておけるのか？","ENG":"Anyway, can this Administration prison hold C.O.s too?","TWN":"話說，管理局的監獄還能關押侵蝕體？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그 아저씨, 호탕하게 생겨선 하는 짓이 영 음습하구만.","JPN":"あのおっさん、豪快そうに見えて陰険なことするんだな。","ENG":"That old guy looks sturdy, but everything he does is shady.","TWN":"那個大叔看起來很豪爽，做的事卻挺陰沉的嘛。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐, 뭐라고?","JPN":"な、なんだと？","ENG":"W-what?!","TWN":"妳、妳說什麼？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"침식체가 왜 이 감옥에……?","JPN":"どうして侵食体がこの監獄に……？","ENG":"Why would a C.O. be in this prison...?","TWN":"侵蝕體為什麼會在這監獄裡……？"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"……아니었군.","JPN":"……違うのかよ。","ENG":"...I guess not, then.","TWN":"……不是這樣啊。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그럼 답은 나왔네.","JPN":"じゃあ、答えは1つだな。","ENG":"That means we've got our answer.","TWN":"那麼答案就很明顯了。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"너희 집 물 샌다는 소리지.","JPN":"どこかに穴が空いてしまったってことだ。","ENG":"Your place is leaking.","TWN":"你們家漏水啊。"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"잔말 말고 뛰어!","JPN":"黙って走れ！","ENG":"Shut up and run!","TWN":"少廢話，快跑！"},"stage":{"bg":"PRISON_SPACE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장! 쓸데없이 구속구 성능만 좋아서…….","JPN":"くそ！　余計に性能が良すぎるんだよこの拘束具……！","ENG":"Damn it! These restraints are annoyingly durable...","TWN":"可惡！束具性能這麼好幹嘛……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"이 감옥 밖은 바다야! 뭘 어떻게 도망치겠다는 거지?","JPN":"監獄の外は海なんだぞ！　何をどうやって逃げるつもりだ？","ENG":"It's the ocean out there! How do you expect to escape?!","TWN":"這監獄外面是海！你打算怎麼逃？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나도 몰라! 비상용 잠수함 같은 것도 없어?!","JPN":"知るかよ！　非常用の潜水艦とかもないのか！？","ENG":"How should I know?! Isn't there some emergency sub or something?!","TWN":"我也不知道！難道沒有緊急用的潛水艇之類的嗎？！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이렇게 된 거, 같이 빠져나가자고!","JPN":"こうなったら、もう一蓮托生して一緒に脱出するしかないぜ！","ENG":"At this point, we're getting out together!","TWN":"既然這樣，就一起逃出去吧！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"버, 범죄자가 도시에 풀려나는 걸 볼 바에는 죽음을 택하겠다!","JPN":"は、犯罪者が都市に放たれるのを見るくらいなら、死を選ぶ！","ENG":"I'd rather die than let a criminal loose in the city!","TWN":"與、與其看著罪犯逃到城市，我寧願選擇死亡！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"말은 그렇게 하지만 내 뒤에 딱 붙어서 따라오고 있잖아!","JPN":"そう言ってるわりには、あたしの後ろにぴったりくっついているけど！","ENG":"Funny how you say that while sticking right behind me!","TWN":"你話是這麼說，但還不是緊緊跟在我後面！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"길이나 안내해!","JPN":"いいから早く道案内しろ！","ENG":"Just lead the way!","TWN":"快帶路！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"다행이다.","JPN":"よかった。","ENG":"Thank goodness.","TWN":"太好了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"아직 남아 있는 잠수정이 있었어!","JPN":"まだ残ってる潜水艇があった！","ENG":"There's still a submersible left!","TWN":"還有留下來的潛水艇！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"얼른 시동 걸어! 이쪽까지 물이 밀려 들어오고 있다고!","JPN":"早くエンジンをかけろ！　ここまで水が入ってきてる！","ENG":"Start it up! Water's already flooding in!","TWN":"快發動！水湧進來了！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"자, 잠깐만 기다려!","JPN":"ち、ちょっと待て！","ENG":"J-just a sec!","TWN":"等、等一下！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"여기 어디 시동키가…","JPN":"どこかにエンジンの鍵が……","ENG":"Where's the ignition...?","TWN":"啟動鑰在哪裡……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"찾았다!","JPN":"あった！","ENG":"Found it!","TWN":"找到了！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_COIN"},{"id":"L10_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"시동이 걸렸어!","JPN":"エンジンかかったぞ！","ENG":"It started!","TWN":"啟動成功！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"버, 범죄자지만 특별히 탑승을 허락한다!","JPN":"は、犯罪者ではあるが、特別に搭乗を許可する！","ENG":"Y-you're a criminal, but I'll allow you aboard, just this once!","TWN":"雖、雖然你是罪犯，但我特別准許妳搭乘！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"너도 얼른 여기로…","JPN":"お前も早くここに……","ENG":"Come on, get in–","TWN":"妳也快過來……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"응?","JPN":"あ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"히이익! 침식체가 탈출로를 비집고 들어왔잖아?!","JPN":"ひいいっ！　侵食体が脱出路に押し入ってきた！？","ENG":"Eek! A C.O. is forcing its way into the escape path?!","TWN":"啊啊啊！侵蝕體鑽進逃生通道了？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"젠장, 내가 일단 탈출로를 뚫을 테니까, 너는 그 틈에 나가!","JPN":"くそ、あたしが脱出路を確保するから、お前はその隙に出ろ！","ENG":"Damn it. I'll clear the way. When I do, you run!","TWN":"可惡。我先開路，你趁機出去！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐라고? 그럼…….","JPN":"何？　それじゃあ……","ENG":"What?! Then you–","TWN":"什麼？那麼……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"카운터니까 어떻게 살 방법이 있겠지.","JPN":"カウンターだし何とか生き残る手はあるだろ。","ENG":"I'm a Counter. I'll figure something out.","TWN":"身為制裁者，總有辦法活下去吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나는 도시를 자유롭게 하고 싶은 거지, 관리국 놈들을 전부 죽이고 싶은 게 아니야.","JPN":"あたしは都市に自由を取り戻したいだけで、管理局のやつらを皆殺しにしたいわけじゃない。","ENG":"I want to free the city, not slaughter every last person in the Administration.","TWN":"我想讓城市自由，不是殺光管理局的人。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나가!","JPN":"行け！","ENG":"Go!","TWN":"快走！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"지, 지원을 부르겠다! 반드시!","JPN":"し、支援を呼んでくる！　必ず！","ENG":"I'll call for backup! I swear!","TWN":"我、我會叫支援！一定會！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CORRECT_FRONTBAY_NULL_NULL","text":{"KOREA":"반드시 살아남아라!","JPN":"必ず生き残るんだぞ！","ENG":"Survive, no matter what!","TWN":"一定要活下來！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CORRECT_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"내가 미쳤지.","JPN":"まったく、どうかしてるよな。","ENG":"I'm out of my mind.","TWN":"我真是瘋了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"도대체 카운터가 물속에서 어떻게 살아남는다고.","JPN":"カウンターが水の中でどうやって生き延びるんだか。","ENG":"How's a Counter supposed to survive underwater?","TWN":"制裁者怎麼可能在水中生存。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"내가 힘의 제약을 받는다고 해서, 잔챙이들을 상대하지 못한다고 생각하면 오산이야.","JPN":"あたしが力を制限されてるからって、雑魚も相手できないと思ったら大きな間違いだぞ。","ENG":"Just because my power's limited doesn't mean I can't handle small fry.","TWN":"就算我的力量受限，也別以為我無法對付小角色。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"덤벼. 길동무는 많으면 많을수록 좋으니까.","JPN":"かかってこい。道連れは多い方がいいからな。","ENG":"Come on. The more company I take down with me, the better.","TWN":"來吧，旅伴越多越好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"바다…속인가?","JPN":"海の……中なのか？","ENG":"I'm under...water?","TWN":"我在……海裡嗎？"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"팔다리가 무거워진다.","JPN":"手足が重くなっていく。","ENG":"My limbs feel heavy.","TWN":"四肢好重。"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"서서히 막혀오는 숨은, 아이러니하게도 내가 아직 살아있음을 느끼게 한다.","JPN":"だんだんと苦しくなる呼吸は、皮肉にも自分がまだ生きていることを実感させる。","ENG":"The tightening in my chest ironically reminds me I'm still alive.","TWN":"逐漸窒息的感覺，諷刺地提醒我自己還活著。"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"약속했다.","JPN":"約束したんだ。","ENG":"I made a promise.","TWN":"我曾許下承諾。"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"강한 힘을 가진 자가 대해적이 되어 관리국으로부터 자유를 되찾자고.","JPN":"強くなって、いつか大海賊になったら、管理局から自由を取り戻すって。","ENG":"That those with great power would become a great pirate and reclaim freedom from the Administration.","TWN":"要讓擁有強大力量的人成為大海盜，從管理局手中奪回自由。"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"약속했다.","JPN":"約束したんだ。","ENG":"I made a promise.","TWN":"我曾許下承諾。"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"대해적이 되어서, 어디 있는지 모를 나의 부모님을…….","JPN":"大海賊になって、どこにいるかわからない両親を……","ENG":"That as a great pirate, I'd find my parents wherever they are...","TWN":"我要成為大海盜，讓不知身在何方的父母……"},"stage":{"bg":"HORIZON_02_A","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"우왁!","JPN":"おわっ！","ENG":"Whoa!","TWN":"哇啊！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"진짜 찔릴 뻔했잖아, 메리 아줌마!","JPN":"本当に刺されるところだったよ、メリーおばさん！","ENG":"I almost got stabbed, Auntie Mary!","TWN":"我差點被刺到了耶，瑪麗阿姨！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"아직 찌르는 것에 있어 망설임이 서려 있구나.","JPN":"まだ剣先に迷いがあるのね。","ENG":"You're still hesitating when it comes to striking.","TWN":"妳還是會在刺擊時有些遲疑呢。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"그런 마음가짐으로 바다에 나가면 먹잇감이 되기 십상이란다.","JPN":"その程度の覚悟で海に出たら、エサになること間違いなしよ。","ENG":"If you go out to sea with that mindset, you'll end up as prey.","TWN":"如果抱著這種心態出海，很容易就會成為獵物。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"으으… 잠깐 방심한 거야.","JPN":"うう……ちょっと油断しただけじゃん。","ENG":"Ugh... I just let my guard down for a second.","TWN":"唔……我只是稍微分心而已。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"아줌마 검을 눈으로 좇아서 막은 걸 칭찬해 줘야 하는 거 아니야?","JPN":"おばさんの剣を目で追って止めたことは褒めてくれてもいいんじゃない？","ENG":"Shouldn't you be praising me for tracking your blade with my eyes?","TWN":"妳不應該誇我用眼睛追蹤而且擋下阿姨的劍嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"훗, 당돌한 것만큼은 칭찬해 주마.","JPN":"ふっ、その生意気なところは褒めてあげる。","ENG":"Heh. I'll praise your boldness at least.","TWN":"哼，至少妳在大膽這方面值得稱讚。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"덕분에 널 볼 때마다 <color=#ffd34c>내 친구</color>가 생각나거든.","JPN":"おかげであなたを見るたびに<color=#ffd34c>私の友だち</color>が思い出されるもの。","ENG":"You remind me of <color=#ffd34c>my friend</color> every time I see you.","TWN":"每次看到妳，就會想起<color=#ffd34c>我的朋友</color>。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"흥, 두고 봐. 언젠간 반드시 이겨줄 테니까.","JPN":"ふん、見ててよ。いつかは必ず勝ってやるから。","ENG":"Hmph. Just watch. I'll beat you someday.","TWN":"哼，等著瞧。我總有一天一定會贏過妳。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"궁금하구나.","JPN":"教えてくれないかな。","ENG":"Riddle me this.","TWN":"我很好奇。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"왜 다른 보육원 아이들과 어울리지 않고 나에게 수련을 시켜달라는 거니?","JPN":"どうして他の孤児院の子たちと遊ばないで、私に稽古つけてくれなんて言ったの？","ENG":"Why don't you play with the other children from the orphanage? Why ask me to train you?","TWN":"妳為什麼不跟其他孤兒院的孩子一起，而是找我訓練呢？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"사람들에게 바다를 돌려주기 위해서!","JPN":"みんなに海を取り戻してあげたいからだよ！","ENG":"To return the sea to the people!","TWN":"為了把海洋還給人們！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"바다를……?","JPN":"海を……？","ENG":"The sea...?","TWN":"海洋……？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"얼마 전에 터커네 아저씨가 어부를 그만둬야 한다고 들었어.","JPN":"この前、ターカーおじさんが漁師をやめないといけないって聞いたんだ。","ENG":"I heard Mr. Tucker had to quit being a fisherman.","TWN":"我前陣子聽說塔克叔叔要放棄當漁夫。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"그것도 다 관리국이 바다로 나가지 못하게 해서 그런 거래!","JPN":"全部、管理局が海に出られないようにしてるからだって！","ENG":"And it's all because the Administration won't let people go out to sea!","TWN":"那也是因為管理局不讓他出海啊！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"또, 또… 막 벽 같은 걸 세워서 사람들을 바다랑 멀어지게 하고 있잖아!","JPN":"それから、ええと……壁みたいなのを建てて、みんなを海から遠ざけてるんだよ！","ENG":"And... and they keep building walls and stuff that push people farther from the ocean!","TWN":"還、還架起牆之類的東西，讓人們遠離海洋！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"흠… 그렇지.","JPN":"ふむ……そうだね。","ENG":"Hmm... true.","TWN":"嗯……沒錯。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"관리국의 방침 때문에 오히려 많은 사람이 직업을 잃게 되었구나.","JPN":"管理局の方針のせいで、かえってたくさんの人が仕事を失うことになったね。","ENG":"Because of the Administration's policies, many have lost their livelihoods.","TWN":"管理局的政策反而很多人失去工作。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"그건 옳지 못해!","JPN":"そんなのおかしいよ！","ENG":"And that's not right!","TWN":"這是不對的！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"바다는 누구의 것도 아니라고!","JPN":"海は誰のものでもないのに！","ENG":"The sea belongs to everyone!","TWN":"海洋不屬於任何人！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"후후, 누굴 닮아서 저렇게 맞는 말만 하는 건지…….","JPN":"ふふ、そうやってズバッと言うところは誰に似たんだか……","ENG":"Fufu, who does she take after to be so straightforward...?","TWN":"呵呵，真不知遺傳誰，只說對的話……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"그래서… 어떻게 바다를 돌려줄 계획이니?","JPN":"それで……どうやって海を取り戻してあげるつもり？","ENG":"So... how do you plan to return the sea?","TWN":"那麼……妳打算怎麼把海洋還給人們？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"음… 관리국의 시니어보다 강해져서, 관리국을 쫓아낼 거야.","JPN":"うーん……管理局のシニアより強くなって、管理局を追い出す。","ENG":"Hmm... I'll get stronger than the Administration's Senior and drive them out.","TWN":"嗯……我要比管理局的Senior更強，趕走管理局。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"어머, 관리국 시니어 곁에는 무지하게 강한 공인 카운터가 있단다?","JPN":"あら、管理局のシニアのそばには、とても強い公認カウンターがいるのよ？","ENG":"Oh my. There's a very strong Official Counter at the Senior's side, you know?","TWN":"哎呀，管理局Senior身邊有超強的公認制裁者啊？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"그 카운터는 어떻게 할 생각이니?","JPN":"そのカウンターはどうするの？","ENG":"What about that Counter?","TWN":"妳打算拿那個制裁者怎麼辦？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"당연히 이겨야지!","JPN":"もちろん勝つ！","ENG":"I'll beat that Counter too!","TWN":"當然要贏過他！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"그걸 위해서 아줌마한테 싸우는 법을 가르쳐달라고 한 거야!","JPN":"そのためにおばさんに戦い方を教えてって言ったんだよ！","ENG":"That's why I asked you to teach me how to fight!","TWN":"所以我才會拜託阿姨教我怎麼戰鬥！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"……그래.","JPN":"……なるほどね。","ENG":"...Very well.","TWN":"……好吧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"그 정도 기개와 패기가 있어야 상대해 줄 맛이 나지.","JPN":"それくらいの意気込みがなきゃ、相手のし甲斐がないわ。","ENG":"With that kind of spirit and fire, you're worth training.","TWN":"要有這種氣概和鬥志，應戰才會有意思。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"응? 그게 무슨 말이야?","JPN":"え？　どういうこと？","ENG":"Huh? What does that mean?","TWN":"嗯？那是什麼意思？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"아무것도 아니란다.","JPN":"何でもないから気にしないで。","ENG":"Nothing.","TWN":"沒什麼。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"그럼, 그럼, 그렇게 되면 사람들이 날 대해적이라고 불러주겠지?","JPN":"じゃあ、じゃあさ、そうなったらみんなあたしのこと大海賊って呼んでくれるよね？","ENG":"Then, then once I do all that, people will call me the great pirate, right?","TWN":"那麼這樣就會叫我大海盜吧？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"대해적……?","JPN":"大海賊……？","ENG":"A great pirate...?","TWN":"大海盜……？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"응. 에이버리처럼 사람들한테 내일을 가져다주는 대해적!","JPN":"うん。エイバリーみたいに、みんなに希望をくれる大海賊！","ENG":"Yeah! A great pirate like Avery, who brings people a tomorrow!","TWN":"嗯。像艾維利一樣，給人們帶來希望的大海盜！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"관리국을 내쫓고, 사람들에게 다시 바다를 드나들 수 있는 자유를 돌려준다면…….","JPN":"管理局を追い出して、みんなにまた海に出入りできる自由を取り戻してあげれば……","ENG":"If I drive out the Administration and let people return to the sea...","TWN":"趕走管理局，讓大家能重新自由出入海洋……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"그럼, 모든 해적들이 우러러보는 대해적이 될 수 있지 않을까?","JPN":"海賊みんなに尊敬される大海賊になれるんじゃないかな？","ENG":"Then all the pirates will look up to me, won't they?","TWN":"那麼，說不定我可以成為所有海盜敬仰的大海盜吧？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"대해적이 돼서 뭘 하고 싶은 건데?","JPN":"大海賊になって何がしたいの？","ENG":"What do you want to do once you become a great pirate?","TWN":"成為大海盜後妳想做什麼？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"음… 바다를 지키러 간 엄마가 다시 날 보러 오게 할 거야!","JPN":"うーんと……海を守りに行ったお母さんに、もう一度あたしに会いに来てもらう！","ENG":"Hmm... I'll make Mom come back to see me!","TWN":"嗯……讓守護海洋的媽媽再回來看我！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"그래. 그런 꿈이라면 나쁘지 않겠구나.","JPN":"そう。そんな夢なら悪くないね。","ENG":"I see. That's not a bad dream.","TWN":"嗯，如果是這樣的夢想也不壞。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"하지만… 가장 중요한 것이 빠져있어.","JPN":"でも……一番大事なことが抜けてるよ。","ENG":"But... you're missing something important.","TWN":"不過……妳漏掉最重要的東西了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"응? 그게 뭐야? 나도 알려줘!","JPN":"え？　何だろう？　あたしにも教えて！","ENG":"Huh? What is it? Tell me!","TWN":"嗯？是什麼？快告訴我！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"후훗, 그런 건 시간이 되면 찾아오는 법이란다.","JPN":"ふふっ、こういうのはその時になれば自ずとわかってくるものだからね。","ENG":"Fufu, that's something you'll find when the time comes.","TWN":"呵呵，等時間到了自然會找上門。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"지금은 네가 하고 싶은 대로 마음껏 날뛰어 보렴.","JPN":"今はあなたのやりたいようにやってみなさい。","ENG":"For now, run wild as much as you want.","TWN":"現在就盡情做妳想做的事吧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"다만, 네가 나아가려는 바다는 파도가 무척이나 거칠겠구나.","JPN":"ただ、あなたが進もうとしている海には、荒れ狂う高波が待っているでしょう。","ENG":"But the sea you wish to face will be harsh.","TWN":"只是妳將踏上的海洋波濤洶湧呢"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"길잡이가 없는 항해는 갈 곳을 잃고 표류하기 마련이거든.","JPN":"道しるべのない航海は、行き先を失って漂流してしまうものだから。","ENG":"A voyage without a guide always drifts without a destination.","TWN":"沒有嚮導的航行，必然會迷失方向而漂流不定。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"으음…….","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님! 일어났습니다!","JPN":"シニア！　目覚めました！","ENG":"Senior! She's awake!","TWN":"Senior！她醒了！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"여긴……?","JPN":"ここは……？","ENG":"Where am I...?","TWN":"這裡是……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"여긴 관리국 본부에 있는 병실이다.","JPN":"ここは管理局本部にある病室だ。","ENG":"This is the infirmary inside the Administration HQ.","TWN":"這裡是管理局本部的病房。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"먼저 잠수정을 타고 나간 녀석은?!","JPN":"先に潜水艇に乗って出たやつは！？","ENG":"What about the guy who took the sub first?!","TWN":"先搭乘潛水艇出去的傢伙呢？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그 녀석은 어떻게 됐어?!","JPN":"あいつはどうなった！？","ENG":"What happened to him?!","TWN":"那傢伙怎麼樣了？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫! 감옥에 있는 동안 교도관과 정이라도 들었나?","JPN":"ハハハ！　監獄にいる間に刑務官と仲良くなったのか？","ENG":"Gah hah hah! Did you grow attached to the guard while you were locked up?","TWN":"哈哈哈！妳坐牢的時候和他有感情啦？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"시, 시끄러워! 그 자식은 어떻게 됐어?!","JPN":"う、うるさい！　あいつはどうなったかって聞いてるんだ！","ENG":"S-shut up! What happened to him?!","TWN":"吵、吵死了！那傢伙怎麼了？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"해저 대감옥의 교도관이라면, 무사히 잠수정을 타고 탈출에 성공했습니다.","JPN":"海底大監獄の刑務官なら、無事潜水艇に乗って脱出に成功しました。","ENG":"The guard from the Deepsea Gaol escaped safely aboard the submersible.","TWN":"如果妳說的是海底大監獄的獄卒，他順利搭乘潛水艇逃生了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"당신을 구하게 된 것도 그분의 지원 요청 덕분이었으니까요.","JPN":"あなたを助けられたのも、その方の支援要請があったからです。","ENG":"And it's thanks to his request for aid that we were able to save you as well.","TWN":"妳能獲救，也是因為他去請求支援。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"아가씨 덕분에 소중한 생명을 하나 구해낼 수 있었어.","JPN":"お嬢さんのおかげで大事な命を救うことができた。","ENG":"Thanks to you, we were able to save a precious life.","TWN":"多虧小姐，才能拯救一條寶貴的生命。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"관리국을 대표해 감사 인사를 전하지.","JPN":"管理局を代表して感謝する。","ENG":"On behalf of the Administration, I offer our gratitude.","TWN":"我代表管理局，向你致謝。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐, 뭐, 뭐, 뭐?","JPN":"な、な、な、なに？","ENG":"W-w-w-what?!","TWN":"什、什、什、什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"핫참,이거,이렇게까지칭찬해주지않아도되는데말이야…웃통깐근육아저씨에게칭찬같은걸들어도전혀기쁘지않거든?","JPN":"はっ、まったく……こ、これくらいのことでそこまで褒めなくてもいいっていうか上半身丸出しのマッチョなおっさんに褒められたってぜんっぜん嬉しくないし？","ENG":"Geez, you don't have to praise me this much... Getting compliments from a beefed-up shirtless old guy doesn't make me happy at all, okay?!","TWN":"哈哈，可以不用這樣這樣感謝我……聽到全身都是肌肉的大叔稱讚我一點都不高興。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"부끄러워하고 있어.","JPN":"照れてるな。","ENG":"She's embarrassed.","TWN":"害羞了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"부끄러워하고 있네요.","JPN":"照れていますね。","ENG":"She is indeed embarrassed.","TWN":"害羞了呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"시, 시끄러워!","JPN":"う、うるさい！","ENG":"S-shut it!","TWN":"吵、吵死了！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐, 됐어.","JPN":"まあ、良い。","ENG":"Enough of that.","TWN":"算了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"중요한 건 아가씨에게서 어느 정도 가능성을 봤다는 거니까.","JPN":"大事なのはお嬢さんからある程度の可能性を見いだせたということだからな。","ENG":"What matters is that I've seen possibilities in you.","TWN":"重點是我看到小姐有一定的可能性。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"가능성? 네가 뭔데 내 가능성을 평가해?","JPN":"可能性？　なんでお前があたしの可能性を評価するんだよ。","ENG":"Possibilities? Who are you to judge that?","TWN":"可能性？你是誰啊，評估我的可能性？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"……근데 무슨 가능성을 얘기하는 거지?","JPN":"……ていうか、何の可能性だ？","ENG":"...And what possibilities are you talking about?","TWN":"……不過你說的可能性是什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"간단히 말해서, 아가씨에게 자유를 선물해 줄 가능성이라고만 말해주지.","JPN":"簡単に、お嬢さんに自由をプレゼントする可能性とだけ言っておこう。","ENG":"Simply put, possibilities to grant you freedom.","TWN":"簡單說，就是小姐有可能獲得自由。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"나랑 간단한 거래를 하는 건 어때?","JPN":"私とちょっとした取引をしないか？","ENG":"How about making a deal with me?","TWN":"要不要和我做個簡單的交易？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"거래……?","JPN":"取引……？","ENG":"A deal...?","TWN":"交易……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그래. 관리국과의 거래가 아닌 나와 거래.","JPN":"ああ。管理局とではなく、私個人との取引だ。","ENG":"Yes. Not with the Administration, just with me.","TWN":"對。不是和管理局，而是和我。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"이 거래를 무사히 끝마친다면 아가씨의 자유는 물론이고…….","JPN":"この取引を無事終わらせることができたら、お嬢さんの自由はもちろん……","ENG":"If you complete this deal successfully, not only will you earn your freedom...","TWN":"如果順利完成這筆交易，小姐不僅能獲得自由……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"관리국이 프론트 베이에서 완전히 물러나는 것을 검토해 보도록 하지.","JPN":"管理局がフロントベイから完全に手を引くことを検討しよう。","ENG":"I'll even consider withdrawing the Administration entirely from Front Bay.","TWN":"管理局也會考慮完全撤出前灣。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"프론트 베이에서… 물러나겠다고……?","JPN":"フロントベイから……手を引く……？","ENG":"Withdraw... from Front Bay...?","TWN":"撤出……前灣……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그 말… 진심이야?","JPN":"その言葉……本気なのか？","ENG":"Are you serious...?","TWN":"你是認真的嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};